@Experimental
final class GroupKey {
	final long[] ids;
	int hash;

	GroupKey(long[] ids) {
		this.ids = ids;
		this.hash = Arrays.hashCode(ids);
	}

	/**
	 * Refreshes a reusable probe key after its ids array has been overwritten in place. Probe keys must never be stored
	 * in a map; use {@link #storedCopy()} for that.
	 */
	GroupKey refill(long[] row, int[] groupSlots) {
		for (int i = 0; i < groupSlots.length; i++) {
			ids[i] = row[groupSlots[i]];
		}
		this.hash = Arrays.hashCode(ids);
		return this;
	}

	/** Recomputes the hash after the ids array was filled externally. */
	void rehash() {
		this.hash = Arrays.hashCode(ids);
	}

	GroupKey storedCopy() {
		return new GroupKey(Arrays.copyOf(ids, ids.length));
	}

	@Override
	public int hashCode() {
		return hash;
	}

	@Override
	public boolean equals(Object obj) {
		return obj instanceof GroupKey && Arrays.equals(ids, ((GroupKey) obj).ids);
	}
}

@Experimental
final class LongHashSet {
	static final long EMPTY = Long.MIN_VALUE;
	long[] table;
	int size;
	int threshold;
	boolean containsEmptySentinel;

	LongHashSet(int expectedSize) {
		int capacity = 1;
		while (capacity < expectedSize * 2) {
			capacity <<= 1;
		}
		table = new long[Math.max(4, capacity)];
		Arrays.fill(table, EMPTY);
		threshold = table.length >>> 1;
	}

	boolean add(long value) {
		if (value == EMPTY) {
			boolean added = !containsEmptySentinel;
			containsEmptySentinel = true;
			if (added) {
				size++;
			}
			return added;
		}
		if (size >= threshold) {
			rehash();
		}
		long[] t = table;
		int mask = t.length - 1;
		int index = mix(value) & mask;
		while (true) {
			long current = t[index];
			if (current == EMPTY) {
				t[index] = value;
				size++;
				return true;
			}
			if (current == value) {
				return false;
			}
			index = (index + 1) & mask;
		}
	}

	boolean contains(long value) {
		if (value == EMPTY) {
			return containsEmptySentinel;
		}
		long[] t = table;
		int mask = t.length - 1;
		int index = mix(value) & mask;
		while (true) {
			long current = t[index];
			if (current == EMPTY) {
				return false;
			}
			if (current == value) {
				return true;
			}
			index = (index + 1) & mask;
		}
	}

	long size() {
		return size;
	}

	/** Unions another set into this one (parallel worker merge). */
	void addAll(LongHashSet other) {
		if (other.containsEmptySentinel) {
			add(EMPTY);
		}
		for (long value : other.table) {
			if (value != EMPTY) {
				add(value);
			}
		}
	}

	void rehash() {
		long[] old = table;
		table = new long[old.length << 1];
		Arrays.fill(table, EMPTY);
		threshold = table.length >>> 1;
		int oldSize = containsEmptySentinel ? 1 : 0;
		size = oldSize;
		for (long value : old) {
			if (value != EMPTY) {
				add(value);
			}
		}
	}

	static int mix(long value) {
		value ^= value >>> 33;
		value *= 0xff51afd7ed558ccdL;
		value ^= value >>> 33;
		value *= 0xc4ceb9fe1a85ec53L;
		value ^= value >>> 33;
		return (int) value;
	}
}
